import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): resolved_version}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for key in all_keys:
    bv = b.get(key)
    av = a.get(key)
    proj, fw, pkg = key
    if bv != av:
        status = 'Added' if not bv else 'Removed' if not av else f'Aligned: {bv} -> {av}'
        changes.append((proj, fw, pkg, bv or '-', av or '-', status))
    else:
        unchanged.append((proj, fw, pkg, av))

if changes:
    print('CHANGES:')
    print(f'{\"Project\":<15} {\"Framework\":<10} {\"Package\":<45} {\"Before\":<12} {\"After\":<12} Status')
    for c in changes:
        print(f'{c[0]:<15} {c[1]:<10} {c[2]:<45} {c[3]:<12} {c[4]:<12} {c[5]}')
else:
    print('No changes detected.')

print()
print('UNCHANGED:')
print(f'{\"Project\":<15} {\"Framework\":<10} {\"Package\":<45} {\"Version\":<12}')
for u in unchanged:
    print(f'{u[0]:<15} {u[1]:<10} {u[2]:<45} {u[3]:<12}')
"

